	/* Complex multiplication */
	static  void ComplexMult(float *y1, float *y2,
		float x1, float x2, float c1, float c2)
	{
		*y1 = MUL_F(x1, c1) + MUL_F(x2, c2);
		*y2 = MUL_F(x2, c1) - MUL_F(x1, c2);
	}

