	void *output_to_PCM(NeAACDecStruct *hDecoder,
		float **input, void *sample_buffer, uint8_t channels,
		uint16_t frame_len, uint8_t format)
	{
		int16_t   *short_sample_buffer = (int16_t*)sample_buffer;
		int32_t   *int_sample_buffer = (int32_t*)sample_buffer;
		float *float_sample_buffer = (float*)sample_buffer;
		double    *double_sample_buffer = (double*)sample_buffer;
		/* Copy output to a standard PCM buffer */
		switch (format)
		{
		case FAAD_FMT_16BIT:
			to_PCM_16bit(hDecoder, input, channels, frame_len, &short_sample_buffer);
			break;
		case FAAD_FMT_24BIT:
			to_PCM_24bit(hDecoder, input, channels, frame_len, &int_sample_buffer);
			break;
		case FAAD_FMT_32BIT:
			to_PCM_32bit(hDecoder, input, channels, frame_len, &int_sample_buffer);
			break;
		case FAAD_FMT_FLOAT:
			to_PCM_float(hDecoder, input, channels, frame_len, &float_sample_buffer);
			break;
		case FAAD_FMT_DOUBLE:
			to_PCM_double(hDecoder, input, channels, frame_len, &double_sample_buffer);
			break;
		}

#ifdef PROFILE
		count = faad_get_ts() - count;
		hDecoder->output_cycles += count;
#endif

		return sample_buffer;
	}

#else

#define DM_MUL FRAC_CONST(0.3203772410170407) // 1/(1+sqrt(2) + 1/sqrt(2))
#define RSQRT2 FRAC_CONST(0.7071067811865475244) // 1/sqrt(2)

	static  float get_sample(float **input, uint8_t channel, uint16_t sample,
		uint8_t down_matrix, uint8_t up_matrix,
		uint8_t *internal_channel)
	{
		if (up_matrix == 1)
			return input[internal_channel[0]][sample];

		if (!down_matrix)
			return input[internal_channel[channel]][sample];

		if (channel == 0)
		{
			float C = MUL_F(input[internal_channel[0]][sample], RSQRT2);
			float L_S = MUL_F(input[internal_channel[3]][sample], RSQRT2);
			float cum = input[internal_channel[1]][sample] + C + L_S;
			return MUL_F(cum, DM_MUL);
		}
		else {
			float C = MUL_F(input[internal_channel[0]][sample], RSQRT2);
			float R_S = MUL_F(input[internal_channel[4]][sample], RSQRT2);
			float cum = input[internal_channel[2]][sample] + C + R_S;
			return MUL_F(cum, DM_MUL);
		}
	}

	void* output_to_PCM(NeAACDecStruct *hDecoder,
		float **input, void *sample_buffer, uint8_t channels,
		uint16_t frame_len, uint8_t format)
	{
		uint8_t ch;
		uint16_t i;
		int16_t *short_sample_buffer = (int16_t*)sample_buffer;
		int32_t *int_sample_buffer = (int32_t*)sample_buffer;

		/* Copy output to a standard PCM buffer */
		for (ch = 0; ch < channels; ch++)
		{
			switch (format)
			{
			case FAAD_FMT_16BIT:
				for (i = 0; i < frame_len; i++)
				{
					int32_t tmp = get_sample(input, ch, i, hDecoder->downMatrix, hDecoder->upMatrix,
						hDecoder->internal_channel);
					if (tmp >= 0)
					{
						tmp += (1 << (REAL_BITS - 1));
						if (tmp >= REAL_CONST(32767))
						{
							tmp = REAL_CONST(32767);
						}
					}
					else {
						tmp += -(1 << (REAL_BITS - 1));
						if (tmp <= REAL_CONST(-32768))
						{
							tmp = REAL_CONST(-32768);
						}
					}
					tmp >>= REAL_BITS;
					short_sample_buffer[(i*channels) + ch] = (int16_t)tmp;
				}
				break;
			case FAAD_FMT_24BIT:
				for (i = 0; i < frame_len; i++)
				{
					int32_t tmp = get_sample(input, ch, i, hDecoder->downMatrix, hDecoder->upMatrix,
						hDecoder->internal_channel);
					if (tmp >= 0)
					{
						tmp += (1 << (REAL_BITS - 9));
						tmp >>= (REAL_BITS - 8);
						if (tmp >= 8388607)
						{
							tmp = 8388607;
						}
					}
					else {
						tmp += -(1 << (REAL_BITS - 9));
						tmp >>= (REAL_BITS - 8);
						if (tmp <= -8388608)
						{
							tmp = -8388608;
						}
					}
					int_sample_buffer[(i*channels) + ch] = (int32_t)tmp;
				}
				break;
			case FAAD_FMT_32BIT:
				for (i = 0; i < frame_len; i++)
				{
					int32_t tmp = get_sample(input, ch, i, hDecoder->downMatrix, hDecoder->upMatrix,
						hDecoder->internal_channel);
					if (tmp >= 0)
					{
						tmp += (1 << (16 - REAL_BITS - 1));
						tmp <<= (16 - REAL_BITS);
					}
					else {
						tmp += -(1 << (16 - REAL_BITS - 1));
						tmp <<= (16 - REAL_BITS);
					}
					int_sample_buffer[(i*channels) + ch] = (int32_t)tmp;
				}
				break;
			case FAAD_FMT_FIXED:
				for (i = 0; i < frame_len; i++)
				{
					float tmp = get_sample(input, ch, i, hDecoder->downMatrix, hDecoder->upMatrix,
						hDecoder->internal_channel);
					int_sample_buffer[(i*channels) + ch] = (int32_t)tmp;
				}
				break;
			}
		}

		return sample_buffer;
	}

#endif


	void ms_decode(ic_stream *ics, ic_stream *icsr, float *l_spec, float *r_spec,
		uint16_t frame_len)
	{
		uint8_t g, b, sfb;
		uint8_t group = 0;
		uint16_t nshort = frame_len / 8;

		uint16_t i, k;
		float tmp;

		if (ics->ms_mask_present >= 1)
		{
			for (g = 0; g < ics->num_window_groups; g++)
			{
				for (b = 0; b < ics->window_group_length[g]; b++)
				{
					for (sfb = 0; sfb < ics->max_sfb; sfb++)
					{
						/* If intensity stereo coding or noise substitution is on
						for a particular scalefactor band, no M/S stereo decoding
						is carried out.
						*/
						if ((ics->ms_used[g][sfb] || ics->ms_mask_present == 2) &&
							!is_intensity(icsr, g, sfb) && !is_noise(ics, g, sfb))
						{
							for (i = ics->swb_offset[sfb]; i < min(ics->swb_offset[sfb + 1], ics->swb_offset_max); i++)
							{
								k = (group*nshort) + i;
								tmp = l_spec[k] - r_spec[k];
								l_spec[k] = l_spec[k] + r_spec[k];
								r_spec[k] = tmp;
							}
						}
					}
					group++;
				}
			}
		}
	}


