	char*  NeAACDecGetErrorMessage(uint8_t errcode)
	{
		if (errcode >= NUM_ERROR_MESSAGES)
			return NULL;
		return err_msg[errcode];
	}

	uint32_t  NeAACDecGetCapabilities(void)
	{
		uint32_t cap = 0;

		/* can't do without it */
		cap += LC_DEC_CAP;

#ifdef MAIN_DEC
		cap += MAIN_DEC_CAP;
#endif
#ifdef LTP_DEC
		cap += LTP_DEC_CAP;
#endif
#ifdef LD_DEC
		cap += LD_DEC_CAP;
#endif
#ifdef ERROR_RESILIENCE
		cap += ERROR_RESILIENCE_CAP;
#endif
		return cap;
	}

